import{_ as t,o as a,c as o,ag as l}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Leave Management","description":"","frontmatter":{},"headers":[],"relativePath":"modules/leave.md","filePath":"modules/leave.md"}'),r={name:"modules/leave.md"};function d(n,e,i,s,h,c){return a(),o("div",null,[...e[0]||(e[0]=[l(`<h1 id="leave-management" tabindex="-1">Leave Management <a class="header-anchor" href="#leave-management" aria-label="Permalink to &quot;Leave Management&quot;">​</a></h1><p>The Leave Management module handles the entire leave lifecycle: configuring leave types and allowances, employee leave submission, multi-step approval workflows, balance tracking, and a visual calendar view. It integrates tightly with the Attendance module to automatically mark approved leave days.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Leave</strong> or <code>/leave</code>. The module is divided into four sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Leave Types</strong></td><td><code>/leave/types</code></td><td>Configure available leave categories</td></tr><tr><td><strong>Leave Requests</strong></td><td><code>/leave/requests</code></td><td>All submitted requests</td></tr><tr><td><strong>Leave Calendar</strong></td><td><code>/leave/calendar</code></td><td>Monthly visual overview</td></tr><tr><td><strong>Leave Balances</strong></td><td><code>/leave/balances</code></td><td>Per-employee balance tracking</td></tr></tbody></table><hr><h2 id="leave-types" tabindex="-1">Leave Types <a class="header-anchor" href="#leave-types" aria-label="Permalink to &quot;Leave Types&quot;">​</a></h2><p>Leave types define the categories of leave available to employees.</p><h3 id="creating-a-leave-type" tabindex="-1">Creating a Leave Type <a class="header-anchor" href="#creating-a-leave-type" aria-label="Permalink to &quot;Creating a Leave Type&quot;">​</a></h3><ol><li>Navigate to <strong>Leave → Leave Types</strong></li><li>Click <strong>Add Leave Type</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Type Name</strong></td><td>Yes</td><td>e.g., <code>Annual Leave</code>, <code>Sick Leave</code>, <code>Casual Leave</code></td></tr><tr><td><strong>Code</strong></td><td>No</td><td>Short code (e.g., <code>AL</code>, <code>SL</code>)</td></tr><tr><td><strong>Annual Allowance</strong></td><td>Yes</td><td>Number of days per year employees receive</td></tr><tr><td><strong>Carry Forward</strong></td><td>No</td><td>Max days that can carry into the next year (0 = no carry forward)</td></tr><tr><td><strong>Requires Documentation</strong></td><td>No</td><td>If enabled, employees must upload a document (e.g., medical certificate for sick leave)</td></tr><tr><td><strong>Half Day Allowed</strong></td><td>No</td><td>Whether employees can take 0.5-day increments</td></tr><tr><td><strong>Paid / Unpaid</strong></td><td>Yes</td><td>Whether this leave type counts as paid</td></tr><tr><td><strong>Applicable Gender</strong></td><td>No</td><td>Restrict to Male, Female, or All (for maternity/paternity)</td></tr><tr><td><strong>Min Notice Days</strong></td><td>No</td><td>How many days in advance the request must be submitted</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Internal description</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><h3 id="default-leave-types-from-demo-seeder" tabindex="-1">Default Leave Types (from Demo Seeder) <a class="header-anchor" href="#default-leave-types-from-demo-seeder" aria-label="Permalink to &quot;Default Leave Types (from Demo Seeder)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Days/Year</th><th>Paid</th><th>Notes</th></tr></thead><tbody><tr><td>Annual Leave</td><td>21</td><td>Yes</td><td>Standard paid holiday</td></tr><tr><td>Sick Leave</td><td>14</td><td>Yes</td><td>Requires medical note after 3 days</td></tr><tr><td>Casual Leave</td><td>7</td><td>Yes</td><td>Short notice leave</td></tr><tr><td>Maternity Leave</td><td>90</td><td>Yes</td><td>Female employees only</td></tr><tr><td>Paternity Leave</td><td>7</td><td>Yes</td><td>Male employees only</td></tr><tr><td>Unpaid Leave</td><td>Unlimited</td><td>No</td><td>No allowance cap</td></tr></tbody></table><hr><h2 id="leave-balances" tabindex="-1">Leave Balances <a class="header-anchor" href="#leave-balances" aria-label="Permalink to &quot;Leave Balances&quot;">​</a></h2><p>Each employee&#39;s leave balance is tracked per leave type per year.</p><h3 id="viewing-balances" tabindex="-1">Viewing Balances <a class="header-anchor" href="#viewing-balances" aria-label="Permalink to &quot;Viewing Balances&quot;">​</a></h3><ol><li>Navigate to <strong>Leave → Balances</strong></li><li>Filter by year and/or employee</li><li>The table shows: Allocated, Used, Pending (awaiting approval), and Remaining days</li></ol><table tabindex="0"><thead><tr><th>Column</th><th>Calculation</th></tr></thead><tbody><tr><td><strong>Allocated</strong></td><td>Annual allowance + carried forward from previous year</td></tr><tr><td><strong>Used</strong></td><td>Approved and completed leave days</td></tr><tr><td><strong>Pending</strong></td><td>Submitted but not yet approved</td></tr><tr><td><strong>Remaining</strong></td><td>Allocated − Used − Pending</td></tr></tbody></table><h3 id="balance-reset" tabindex="-1">Balance Reset <a class="header-anchor" href="#balance-reset" aria-label="Permalink to &quot;Balance Reset&quot;">​</a></h3><p>Leave balances reset at the start of each financial year (configured in Settings). The system:</p><ol><li>Calculates any carry-forward entitlements</li><li>Creates new balance records for the new year</li><li>Resets the used count to 0</li></ol><hr><h2 id="submitting-a-leave-request" tabindex="-1">Submitting a Leave Request <a class="header-anchor" href="#submitting-a-leave-request" aria-label="Permalink to &quot;Submitting a Leave Request&quot;">​</a></h2><h3 id="employee-self-service" tabindex="-1">Employee Self-Service <a class="header-anchor" href="#employee-self-service" aria-label="Permalink to &quot;Employee Self-Service&quot;">​</a></h3><p>Employees can submit their own leave requests:</p><ol><li>Navigate to <strong>Leave → My Requests</strong></li><li>Click <strong>Apply for Leave</strong></li><li>Fill in the form:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Leave Type</strong></td><td>Yes</td><td>Select from available types</td></tr><tr><td><strong>Start Date</strong></td><td>Yes</td><td>First day of leave</td></tr><tr><td><strong>End Date</strong></td><td>Yes</td><td>Last day of leave</td></tr><tr><td><strong>Half Day</strong></td><td>No</td><td>Toggle for a half-day request (shows AM/PM option)</td></tr><tr><td><strong>Reason</strong></td><td>No</td><td>Optional explanation</td></tr><tr><td><strong>Supporting Document</strong></td><td>Conditional</td><td>Required if the leave type has <code>Requires Documentation</code> enabled</td></tr></tbody></table><ol start="4"><li>Click <strong>Submit</strong></li></ol><p>The system:</p><ul><li>Calculates the total leave days (excluding weekends and holidays)</li><li>Checks that the employee has sufficient balance</li><li>Creates the request with status <strong>Pending</strong></li><li>Notifies the reporting manager via email (if SMTP configured)</li></ul><div class="warning custom-block"><p class="custom-block-title">Insufficient Balance</p><p>If the employee does not have enough remaining days, the system shows a warning. The request can still be submitted (for manager override), but the manager is alerted to the balance issue.</p></div><h3 id="hr-admin-submitting-on-behalf-of-employee" tabindex="-1">HR/Admin Submitting on Behalf of Employee <a class="header-anchor" href="#hr-admin-submitting-on-behalf-of-employee" aria-label="Permalink to &quot;HR/Admin Submitting on Behalf of Employee&quot;">​</a></h3><p>HR staff can submit leave on behalf of any employee:</p><ol><li>Navigate to <strong>Leave → Requests → Add Request</strong></li><li>Select the <strong>Employee</strong> from the dropdown</li><li>Complete the form as above</li><li>Click <strong>Submit</strong></li></ol><hr><h2 id="approval-workflow" tabindex="-1">Approval Workflow <a class="header-anchor" href="#approval-workflow" aria-label="Permalink to &quot;Approval Workflow&quot;">​</a></h2><p>Leave requests follow this status flow:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pending → Approved</span></span>
<span class="line"><span>        → Rejected</span></span>
<span class="line"><span>        → Cancelled (by employee, before approval)</span></span></code></pre></div><h3 id="approving-a-request" tabindex="-1">Approving a Request <a class="header-anchor" href="#approving-a-request" aria-label="Permalink to &quot;Approving a Request&quot;">​</a></h3><ol><li>Navigate to <strong>Leave → Requests</strong></li><li>Find the pending request (filter by Status = Pending)</li><li>Click <strong>Review</strong></li><li>Review the request details, dates, and remaining balance</li><li>Click <strong>Approve</strong> or <strong>Reject</strong></li><li>Add an optional note (required for rejections)</li></ol><p>On approval:</p><ul><li>The leave balance is updated (pending days move to used)</li><li>The attendance records for the leave period are updated to <strong>On Leave</strong> status</li><li>The employee is notified via email</li></ul><p>On rejection:</p><ul><li>The balance is not deducted</li><li>The employee is notified with the rejection reason</li></ul><h3 id="manager-approval-flow" tabindex="-1">Manager Approval Flow <a class="header-anchor" href="#manager-approval-flow" aria-label="Permalink to &quot;Manager Approval Flow&quot;">​</a></h3><p>If a manager is assigned as the employee&#39;s reporting manager:</p><ul><li>The manager receives an email notification on submission</li><li>The manager can approve/reject from their <strong>Leave → Team Requests</strong> view</li><li>HR Managers can override any approval</li></ul><hr><h2 id="half-day-leave" tabindex="-1">Half-Day Leave <a class="header-anchor" href="#half-day-leave" aria-label="Permalink to &quot;Half-Day Leave&quot;">​</a></h2><p>When <strong>Half Day Allowed</strong> is enabled for a leave type:</p><ol><li>Employee toggles <strong>Half Day</strong> when submitting</li><li>Selects <strong>Morning</strong> or <strong>Afternoon</strong></li><li>The system deducts <strong>0.5 days</strong> from the balance</li><li>The attendance record shows <strong>Half Day</strong> status</li></ol><hr><h2 id="leave-calendar" tabindex="-1">Leave Calendar <a class="header-anchor" href="#leave-calendar" aria-label="Permalink to &quot;Leave Calendar&quot;">​</a></h2><p>The leave calendar at <code>/leave/calendar</code> shows a monthly view of:</p><ul><li>All approved leave requests (colour-coded by leave type)</li><li>Public holidays</li><li>Weekends</li></ul><p>Use it to:</p><ul><li>Spot conflicts (multiple team members on leave on the same day)</li><li>Plan leave allocation</li><li>Review team availability before approving new requests</li></ul><h3 id="calendar-views" tabindex="-1">Calendar Views <a class="header-anchor" href="#calendar-views" aria-label="Permalink to &quot;Calendar Views&quot;">​</a></h3><table tabindex="0"><thead><tr><th>View</th><th>Description</th></tr></thead><tbody><tr><td><strong>Month</strong></td><td>Full month grid with day-by-day leave indicators</td></tr><tr><td><strong>Team</strong></td><td>Filter by department to see only one team&#39;s leave</td></tr><tr><td><strong>Employee</strong></td><td>Focus on one employee&#39;s leave history</td></tr></tbody></table><hr><h2 id="exporting-leave-data" tabindex="-1">Exporting Leave Data <a class="header-anchor" href="#exporting-leave-data" aria-label="Permalink to &quot;Exporting Leave Data&quot;">​</a></h2><p>From <strong>Leave → Requests</strong>:</p><ol><li>Filter by date range, type, and/or status</li><li>Click <strong>Export CSV</strong></li><li>File downloads as <code>leave-requests-YYYY-MM-DD.csv</code></li></ol><p>The export includes all leave request details including status, reason, and approver name.</p>`,67)])])}const v=t(r,[["render",d]]);export{g as __pageData,v as default};
